CREATE TABLE cost_types
(
	id serial,
	name character varying (127) NOT NULL,
	description text DEFAULT NULL,
	CONSTRAINT pk_cost_types PRIMARY KEY (id)
);
CREATE INDEX i_cost_types_name ON cost_types (name);

